<span class="line"><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">ADD</span><span style="--shiki-light:#393A34;--shiki-dark:#DBD7CAEE;"> archive.tar.gz /app/    # ADD 会自动解压 tar，其他行为跟 COPY 一样</span></span>
